/* eslint-disable react/no-unknown-property */

import { useEffect, useMemo, useRef, useState } from 'react';
import { Canvas, extend, useFrame } from '@react-three/fiber';
import { Environment, Lightformer, useGLTF, useTexture } from '@react-three/drei';
import {
  BallCollider,
  CuboidCollider,
  Physics,
  RigidBody,
  useRopeJoint,
  useSphericalJoint,
} from '@react-three/rapier';
import { MeshLineGeometry, MeshLineMaterial } from 'meshline';
import * as THREE from 'three';
import './Lanyard.css';

extend({ MeshLineGeometry, MeshLineMaterial });

export default function Lanyard({
  cameraDistance = 22,
  position = [0, 0, cameraDistance],
  gravity = [0, -40, 0],
  fov = 20,
  transparent = true,
  cardUrl = `${import.meta.env.BASE_URL}assets/lanyard/card.glb`,
  lanyardTextureUrl = `${import.meta.env.BASE_URL}assets/lanyard/lanyard.png`,
}) {
  const [isMobile, setIsMobile] = useState(
    () => typeof window !== 'undefined' && window.matchMedia('(max-width: 768px)').matches
  );

  useEffect(() => {
    const media = window.matchMedia('(max-width: 768px)');
    const handler = () => setIsMobile(media.matches);
    handler();

    if (media.addEventListener) media.addEventListener('change', handler);
    else media.addListener(handler);

    return () => {
      if (media.removeEventListener) media.removeEventListener('change', handler);
      else media.removeListener(handler);
    };
  }, []);

  const cameraPosition = useMemo(() => {
    if (Array.isArray(position) && position.length === 3) return position;
    return [0, 0, cameraDistance];
  }, [cameraDistance, position]);

  const [hasInteracted, setHasInteracted] = useState(false);

  return (
    <div className="lanyard-wrapper" aria-hidden="true">
      <div className={`lanyard-tooltip ${hasInteracted ? 'hidden' : ''}`}>
        <div className="lanyard-tooltip-icon">
          <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <path d="M5 9c0-1.5 1-3 2.5-3A2.5 2.5 0 0 1 10 8.5v3c0-1.5 1-3 2.5-3A2.5 2.5 0 0 1 15 11v1" />
            <path d="M10 8.5v-3C10 4 11 2.5 12.5 2.5S15 4 15 5.5v3.5" />
            <path d="M15 9c0-1.5 1-3 2.5-3A2.5 2.5 0 0 1 20 8.5v7.5A6.5 6.5 0 0 1 13.5 22.5h-2A6.5 6.5 0 0 1 5 16v-7.5" />
            <path d="M19 12h-4" />
          </svg>
        </div>
        <span>Grab & Pull</span>
      </div>
      <Canvas
        camera={{ position: cameraPosition, fov }}
        dpr={[1, isMobile ? 1.5 : 2]}
        gl={{ alpha: transparent, antialias: true }}
        onCreated={({ gl }) => gl.setClearColor(new THREE.Color(0x000000), transparent ? 0 : 1)}
      >
        <ambientLight intensity={Math.PI} />

        <Physics gravity={gravity} timeStep={isMobile ? 1 / 30 : 1 / 60}>
          <Band
            isMobile={isMobile}
            cardUrl={cardUrl}
            lanyardTextureUrl={lanyardTextureUrl}
            onDragStart={() => setHasInteracted(true)}
          />
        </Physics>

        <Environment blur={0.75}>
          <Lightformer
            intensity={2}
            color="white"
            position={[0, -1, 5]}
            rotation={[0, 0, Math.PI / 3]}
            scale={[100, 0.1, 1]}
          />
          <Lightformer
            intensity={3}
            color="white"
            position={[-1, -1, 1]}
            rotation={[0, 0, Math.PI / 3]}
            scale={[100, 0.1, 1]}
          />
          <Lightformer
            intensity={3}
            color="white"
            position={[1, 1, 1]}
            rotation={[0, 0, Math.PI / 3]}
            scale={[100, 0.1, 1]}
          />
          <Lightformer
            intensity={10}
            color="white"
            position={[-10, 0, 14]}
            rotation={[0, Math.PI / 2, Math.PI / 3]}
            scale={[100, 10, 1]}
          />
        </Environment>
      </Canvas>
    </div>
  );
}

function Band({
  maxSpeed = 50,
  minSpeed = 0,
  isMobile = false,
  cardUrl,
  lanyardTextureUrl,
  onDragStart
}) {
  const band = useRef();
  const fixed = useRef();
  const j1 = useRef();
  const j2 = useRef();
  const j3 = useRef();
  const card = useRef();

  const vec = useMemo(() => new THREE.Vector3(), []);
  const ang = useMemo(() => new THREE.Vector3(), []);
  const rot = useMemo(() => new THREE.Vector3(), []);
  const dir = useMemo(() => new THREE.Vector3(), []);

  const segmentProps = useMemo(
    () => ({
      type: 'dynamic',
      canSleep: true,
      colliders: false,
      angularDamping: 4,
      linearDamping: 4,
    }),
    []
  );

  const { nodes, materials } = useGLTF(cardUrl);
  const texture = useTexture(lanyardTextureUrl);

  const curve = useMemo(
    () =>
      new THREE.CatmullRomCurve3([
        new THREE.Vector3(),
        new THREE.Vector3(),
        new THREE.Vector3(),
        new THREE.Vector3(),
      ]),
    []
  );

  const [dragged, setDragged] = useState(false);
  const [hovered, setHovered] = useState(false);

  // Slightly longer strap
  useRopeJoint(fixed, j1, [[0, 0, 0], [0, 0, 0], 1.35]);
  useRopeJoint(j1, j2, [[0, 0, 0], [0, 0, 0], 1.35]);
  useRopeJoint(j2, j3, [[0, 0, 0], [0, 0, 0], 1.35]);
  useSphericalJoint(j3, card, [
    [0, 0, 0],
    [0, 1.5, 0],
  ]);

  useEffect(() => {
    if (!hovered) return;
    document.body.style.cursor = dragged ? 'grabbing' : 'grab';
    return () => {
      document.body.style.cursor = 'auto';
    };
  }, [hovered, dragged]);

  useFrame((state, delta) => {
    if (dragged) {
      vec.set(state.pointer.x, state.pointer.y, 0.5).unproject(state.camera);
      dir.copy(vec).sub(state.camera.position).normalize();
      vec.add(dir.multiplyScalar(state.camera.position.length()));
      [card, j1, j2, j3, fixed].forEach((ref) => ref.current?.wakeUp());

      // Update target position
      card.current?.setNextKinematicTranslation({
        x: vec.x - dragged.x,
        y: vec.y - dragged.y,
        z: vec.z - dragged.z,
      });

      // Apply physical rotation matching movement velocity for organic swing
      const dragVelocityX = state.pointer.x - (card.current?.lastPointerX || state.pointer.x);
      card.current.lastPointerX = state.pointer.x;
      card.current?.setNextKinematicRotation(
        new THREE.Quaternion().setFromEuler(
          new THREE.Euler(
            (vec.y - dragged.y) * -0.05, 
            dragVelocityX * 5, 
            dragVelocityX * -2
          )
        )
      );
    }

    if (fixed.current && j1.current && j2.current && j3.current && card.current) {
      [j1, j2].forEach((ref) => {
        if (!ref.current.lerped) ref.current.lerped = new THREE.Vector3().copy(ref.current.translation());
        const clampedDistance = Math.max(0.1, Math.min(1, ref.current.lerped.distanceTo(ref.current.translation())));
        ref.current.lerped.lerp(
          ref.current.translation(),
          delta * (minSpeed + clampedDistance * (maxSpeed - minSpeed))
        );
      });

      curve.points[0].copy(j3.current.translation());
      curve.points[1].copy(j2.current.lerped);
      curve.points[2].copy(j1.current.lerped);
      curve.points[3].copy(fixed.current.translation());

      band.current?.geometry?.setPoints(curve.getPoints(isMobile ? 16 : 32));

      ang.copy(card.current.angvel());
      rot.copy(card.current.rotation());

      // Auto-spin physics when not being dragged
      if (!dragged) {
        // Keep waking it up so it never goes to sleep and stops spinning
        card.current.wakeUp();
        // Give it a subtle continuous push on the Y axis to keep it spinning smoothly
        const currentSpinY = ang.y;
        const targetSpinY = 1.2; // Desired spin speed

        // Gentle acceleration towards target spin speed
        const spinForce = (targetSpinY - currentSpinY) * delta * 5; 

        card.current.setAngvel({ 
          x: ang.x * 0.98, // damp x swinging faster
          y: ang.y + spinForce, // continuous spin
          z: ang.z * 0.98  // damp z swinging faster
        });
      } else {
        // Adjust angular velocity to naturally dampen and spin while dragged
        card.current.setAngvel({ x: ang.x, y: ang.y - rot.y * 0.25, z: ang.z });
      }
    }
  });

  curve.curveType = 'chordal';
  texture.wrapS = texture.wrapT = THREE.RepeatWrapping;

  return (
    <>
      <group position={[0, 5, 0]}>
        <RigidBody ref={fixed} {...segmentProps} type="fixed" />

        <RigidBody position={[0.75, 0, 0]} ref={j1} {...segmentProps}>
          <BallCollider args={[0.1]} />
        </RigidBody>

        <RigidBody position={[1.5, 0, 0]} ref={j2} {...segmentProps}>
          <BallCollider args={[0.1]} />
        </RigidBody>

        <RigidBody position={[2.25, 0, 0]} ref={j3} {...segmentProps}>
          <BallCollider args={[0.1]} />
        </RigidBody>

        <RigidBody
          position={[3.0, 0, 0]}
          ref={card}
          {...segmentProps}
          type={dragged ? 'kinematicPosition' : 'dynamic'}
        >
          <CuboidCollider args={[0.8, 1.125, 0.01]} />

          <group
            scale={2.25}
            position={[0, -1.2, -0.05]}
            onPointerOver={() => setHovered(true)}
            onPointerOut={() => setHovered(false)}
            onPointerUp={(e) => {
              e.target.releasePointerCapture(e.pointerId);
              setDragged(false);

              // Apply flick spin on release
              if (card.current) {
                const spinForce = (Math.random() - 0.5) * 4;
                card.current.applyTorqueImpulse({ x: 0, y: spinForce, z: (Math.random() - 0.5) * 2 }, true);
              }
            }}
            onPointerDown={(e) => {
              e.target.setPointerCapture(e.pointerId);
              setDragged(new THREE.Vector3().copy(e.point).sub(vec.copy(card.current.translation())));
              if (onDragStart) onDragStart();
            }}
          >
            <mesh geometry={nodes.card?.geometry}>
              <meshPhysicalMaterial
                map={materials?.base?.map}
                map-anisotropy={16}
                clearcoat={isMobile ? 0 : 1}
                clearcoatRoughness={0.15}
                roughness={0.9}
                metalness={0.8}
              />
            </mesh>
            <mesh geometry={nodes.clip?.geometry} material={materials?.metal} material-roughness={0.3} />
            <mesh geometry={nodes.clamp?.geometry} material={materials?.metal} />
          </group>
        </RigidBody>
      </group>

      <mesh ref={band}>
        <meshLineGeometry />
        <meshLineMaterial
          color="white"
          depthTest={false}
          resolution={isMobile ? [1000, 2000] : [1000, 1000]}
          useMap
          map={texture}
          repeat={[-4, 1]}
          lineWidth={1}
        />
      </mesh>
    </>
  );
}

useGLTF.preload(`${import.meta.env.BASE_URL}assets/lanyard/card.glb`);

